Install:
uvx --from git+https://github.com/redis/mcp-redis.git redis-mcp-server --url redis://localhost:6379/0 && claude mcp list

Config:
{
  "redis": {
    "args": [
      "--from",
      "git+https://github.com/redis/mcp-redis.git",
      "redis-mcp-server",
      "--url",
      "redis://localhost:6379/0"
    ],
    "command": "uvx"
  }
}

